export function getRoadmapPrompt(domain: string) {
    let matchedData = "";
    const lowerDomain = domain.toLowerCase();
    
    // Find best match in domain rules
    for (const [key, value] of Object.entries(domainData)) {
        if (key.toLowerCase().includes(lowerDomain) || lowerDomain.includes(key.toLowerCase().split(' ')[0])) {
            matchedData = value;
            break;
        }
    }
    
    if (!matchedData) {
        // Fallback to first domain if not found (unexpected)
        matchedData = Object.values(domainData)[0] as string;
    }

    return basePrompt + "\n\n### Context for your domain:\n" + matchedData;
}

export function getDomainContext(domain: string): string {
    // Fixed: allow API routes to reuse domain context without enforcing the legacy JSON schema
    let matchedData = "";
    const lowerDomain = domain.toLowerCase();
    for (const [key, value] of Object.entries(domainData)) {
        if (key.toLowerCase().includes(lowerDomain) || lowerDomain.includes(key.toLowerCase().split(' ')[0])) {
            matchedData = value;
            break;
        }
    }
    if (!matchedData) matchedData = Object.values(domainData)[0] as string;
    return matchedData;
}
